import{c as e,Q as a,j as n,m as d}from"./chunks/framework.CdiUUa3G.js";const g=JSON.parse('{"title":"ADR-031 — i18n language list and rollout waves","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-031.md","filePath":"adr/ADR-031.md"}'),i={name:"adr/ADR-031.md"};function o(r,t,s,l,c,u){return a(),n("div",null,[...t[0]||(t[0]=[d('<h1 id="adr-031-—-i18n-language-list-and-rollout-waves" tabindex="-1">ADR-031 — i18n language list and rollout waves <a class="header-anchor" href="#adr-031-—-i18n-language-list-and-rollout-waves" aria-label="Permalink to &quot;ADR-031 — i18n language list and rollout waves&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-05-04 RFC anchor · <code>docs/rfc/RFC-010.md</code> (closed by this ADR + ADR-032 + ADR-033) Supersedes · — (extends ADR-017&#39;s locale-overlay architecture)</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>ADR-017 locked the i18n <em>architecture</em> (Paraglide-js for UI strings + locale-overlay JSON for editorial content) but left the <em>language selection</em> and rollout sequencing open. RFC-010 explored eleven candidate languages by unioning &quot;world top-N speakers&quot; with &quot;active space-faring nations&quot; and proposed a priority order; this ADR closes that question.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Eleven supported locales, in this priority order:</p><table tabindex="0"><thead><tr><th>#</th><th>Language</th><th>Code</th><th>Script</th><th>Direction</th><th>Wave</th></tr></thead><tbody><tr><td>1</td><td>Spanish</td><td><code>es</code></td><td>Latin</td><td>LTR</td><td>1</td></tr><tr><td>2</td><td>Mandarin (Simplified)</td><td><code>zh-CN</code></td><td>CJK</td><td>LTR</td><td>2</td></tr><tr><td>3</td><td>French</td><td><code>fr</code></td><td>Latin</td><td>LTR</td><td>1</td></tr><tr><td>4</td><td>Japanese</td><td><code>ja</code></td><td>CJK + Hiragana/Katakana</td><td>LTR</td><td>2</td></tr><tr><td>5</td><td>German</td><td><code>de</code></td><td>Latin</td><td>LTR</td><td>1</td></tr><tr><td>6</td><td>Hindi</td><td><code>hi</code></td><td>Devanagari</td><td>LTR</td><td>3</td></tr><tr><td>7</td><td>Portuguese (BR)</td><td><code>pt-BR</code></td><td>Latin</td><td>LTR</td><td>1</td></tr><tr><td>8</td><td>Arabic</td><td><code>ar</code></td><td>Arabic</td><td><strong>RTL</strong></td><td>3</td></tr><tr><td>9</td><td>Korean</td><td><code>ko</code></td><td>Hangul</td><td>LTR</td><td>2</td></tr><tr><td>10</td><td>Russian</td><td><code>ru</code></td><td>Cyrillic</td><td>LTR</td><td>3</td></tr><tr><td>11</td><td>Italian</td><td><code>it</code></td><td>Latin</td><td>LTR</td><td>1</td></tr></tbody></table><p><strong>Wave structure</strong> groups by script-system risk, not priority:</p><ul><li><strong>Wave 1 — Latin script.</strong> Zero new infrastructure (existing fonts cover Latin extended). Languages: Spanish, French, German, Portuguese (BR), Italian.</li><li><strong>Wave 2 — CJK.</strong> Requires CJK font loading strategy (deferred to a follow-up ADR scheduled with Wave 2). Languages: Mandarin, Japanese, Korean.</li><li><strong>Wave 3 — non-Latin / non-CJK.</strong> Mixed script concerns: Devanagari (font only), Cyrillic (font verification), Arabic (RTL CSS audit — deferred to a follow-up ADR scheduled with Wave 3). Languages: Hindi, Arabic, Russian.</li></ul><p><strong>Scheduling</strong>: v0.3.x ships Spanish only (proof-of-concept; tracked in #17 + foundation in #33 + glossary in #34). Remaining Wave 1 languages move to PLANNED but unscheduled (umbrella tracker #36). Wave 2 (#37) and Wave 3 (#38) are gated on the script-specific follow-up ADRs and remain backlog.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>Priority order optimises for <strong>reach × STEM-audience-engagement × implementation-effort</strong>:</p><ul><li>Spanish first — largest new reach for lowest effort; strong Latin-American + Spanish STEM communities; existing infra suffices.</li><li>Mandarin second — China is a Tier-1 Mars/Moon player (CNSA Tianwen, CMSA crewed missions); 1.1B speakers; the CJK font work pays off across three languages (Wave 2).</li><li>The wave-by-script grouping decouples <em>priority</em> from <em>infra readiness</em>: high-priority languages from different waves can be scheduled independently as their gating ADRs land.</li></ul><p>The eleven-language list is bounded — RFC-010 considered Hebrew, Dutch, and others but excluded them on the priority×reach criterion; this ADR doesn&#39;t preclude future additions but makes them an explicit ADR superseding event.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Ship all eleven at once</strong> — maximises reach in one milestone; risk is uneven quality across languages and a long blocking critical path on the slowest gating ADR; rejected.</li><li><strong>Ship only Wave 1 ever</strong> — simplifies infra forever but excludes ~3B speakers (CJK + Hindi + Arabic + Russian); rejected on reach grounds.</li><li><strong>Pure community-contribution model with no priority list</strong> — open <code>translations/</code> and let contributors fill any language; rejected because cold-start needs a defined first language and a glossary, and quality-control without a priority order leaves orphan locales.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: clear priority order means each language ticket has unambiguous &quot;next up&quot; status; wave grouping isolates infra work; v0.3.x scope stays tight (Spanish only); future language additions are an explicit ADR-supersession event, not implicit drift.</p><p>Negative: every Wave 2 / Wave 3 language is gated on a not-yet-written follow-up ADR (CJK font strategy; RTL CSS strategy); umbrella trackers (#36 / #37 / #38) need active maintenance as per-language tickets spawn off them.</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><ul><li><code>src/lib/locale.ts</code> (created by #33) maintains the supported-locale set; this ADR is the source of truth for what &quot;supported&quot; means.</li><li><code>&lt;LocalePicker&gt;</code> (created by #33) sources the dropdown options from the same set.</li><li>Per-language tickets get filed off the relevant umbrella tracker (#36/#37/#38) when each is scheduled, modelled on #17.</li></ul>',21)])])}const p=e(i,[["render",o]]);export{g as __pageData,p as default};
